import sys
import math
from collections import deque

def solve(nums: list[int]) -> int:
    n = len(nums)
    if n == 0:
        return 0

    max_num = 10**6
    # Sieve of Eratosthenes
    is_prime = [True] * (max_num + 1)
    is_prime[0] = is_prime[1] = False
    for i in range(2, int(math.isqrt(max_num)) + 1):
        if is_prime[i]:
            for j in range(i*i, max_num + 1, i):
                is_prime[j] = False

    # Smallest Prime Factor (SPF)
    spf = list(range(max_num + 1))
    for i in range(2, int(math.isqrt(max_num)) + 1):
        if spf[i] == i:  # i is prime
            for j in range(i*i, max_num + 1, i):
                if spf[j] == j:
                    spf[j] = i

    # Build prime_indices
    prime_indices = dict()
    for idx, x in enumerate(nums):
        if x == 1:
            continue
        factors = set()
        temp = x
        while temp > 1:
            p = spf[temp]
            factors.add(p)
            while temp % p == 0:
                temp //= p
        for p in factors:
            if p not in prime_indices:
                prime_indices[p] = []
            prime_indices[p].append(idx)

    # BFS
    visited = [-1] * n
    q = deque()
    q.append(0)
    visited[0] = 0

    while q:
        i = q.popleft()
        if i == n - 1:
            return visited[i]
        # Check adjacent indices
        for j in [i - 1, i + 1]:
            if 0 <= j < n and visited[j] == -1:
                visited[j] = visited[i] + 1
                q.append(j)
        # Check if nums[i] is a prime
        if is_prime[nums[i]]:
            p = nums[i]
            if p in prime_indices:
                for j in prime_indices[p]:
                    if j != i and visited[j] == -1:
                        visited[j] = visited[i] + 1
                        q.append(j)

    return visited[n - 1]
